for(const item of $input.all()){
  const row=item.json;
  if(!row||Object.keys(row).length===0)continue;
  if(row.__noResults||row.__error)continue;
  const tituloKey=Object.keys(row).find(k=>k.startsWith('Nombre')||k.startsWith('nombre'));
  const titulo=decodeHtml((tituloKey?String(row[tituloKey]):'')||'');
  const numeroKey=Object.keys(row).find(k=>{const kn=_normKey(k);return(kn.includes('numero')||kn.includes('nro'))&&(kn.includes('proceso')||kn.includes('expediente')||kn.includes('proc'));});
  const numero=numeroKey?String(row[numeroKey]).trim():'';
  if(!numero||numero.length<5||!numero.includes('/'))continue;
  const organismo=decodeHtml(getCol(row,['Unidad Ejecutora','Unidad ejecutora','unidad ejecutora','Organismo','organismo','Servicio Administrativo Financiero']));
  const fechaCierreRaw=getCol(row,['Fecha de Apertura','Fecha de apertura','Fecha apertura','Fecha Apertura']);
  const fechaPubRaw=getCol(row,['Fecha de Publicacion','Fecha Publicacion','Fecha publicacion']);
  const montoRaw=getCol(row,['Monto Estimado','Presupuesto Oficial','Monto estimado'])||null;
  const monto=montoRaw?parseFloat(String(montoRaw).replace(/[$.,\s]/g,'').replace(',','.')):null;
  const tituloNorm=norm(titulo);
  let rubroMatch=null;
  for(const[rubro,keywords]of Object.entries(RUBROS)){if(keywords.some(kw=>tituloNorm.includes(norm(kw)))){rubroMatch=rubro;break;}}
  let fechaCierreISO=null,diasAlCierre=null;
  const mc=String(fechaCierreRaw).match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if(mc){const[,d,mo,y]=mc;fechaCierreISO=y+'-'+mo.padStart(2,'0')+'-'+d.padStart(2,'0');diasAlCierre=Math.ceil((new Date(fechaCierreISO+'T23:59:59')-new Date(hoyISO+'T00:00:00'))/86400000);}
  let fechaPubISO=null;
  const mp=String(fechaPubRaw).match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
  if(mp){const[,d,mo,y]=mp;fechaPubISO=y+'-'+mo.padStart(2,'0')+'-'+d.padStart(2,'0');}
  if(fechaCierreISO&&diasAlCierre!==null&&diasAlCierre<0)continue;
  let score=rubroMatch?50:0;
  if(monto!==null&&!isNaN(monto)){if(monto>=5000000)score+=15;else if(monto>=1000000)score+=10;else if(monto>=500000)score+=5;else score+=2;}else score+=5;
  if(diasAlCierre!==null){if(diasAlCierre<=0)score+=0;else if(diasAlCierre<=3)score+=5;else if(diasAlCierre<=7)score+=10;else if(diasAlCierre<=15)score+=15;else score+=8;}
  const prioridad=score>=70?'alta':score>=40?'media':'baja';
  if(prioridad==='alta')alta++;else if(prioridad==='media')media++;else baja++;
  licitaciones.push({portal:'nacional',numero,titulo:titulo.trim(),organismo:String(organismo).trim(),rubro:rubroMatch??'sin_clasificar',monto_estimado:(monto!==null&&!isNaN(monto))?monto:null,fecha_publicacion:fechaPubISO,fecha_cierre:fechaCierreISO,url:null,estado:'nueva',score,prioridad,participacion_previa:false});
}
return[{json:{licitaciones,count:licitaciones.length,alta,media,baja,fechaHoy:hoyDisplay}}];

const stats=$input.first().json;
const todas=stats.licitaciones||[];
if(!todas.length){
  return[{json:{licitaciones:[],count:0,count_total:0,count_nuevas:0,count_existentes:0,alta:0,media:0,baja:0,fechaHoy:stats.fechaHoy}}];
}
let existentesSet=new Set();
try{
  const supaUrl='https://azwplnjlkfcszbrfaehv.supabase.co';
  const supaKey=$env.SUPABASE_SERVICE_KEY||'';
  if(supaKey){
    const res=await fetch(supaUrl+'/rest/v1/licitaciones?portal=eq.nacional&select=numero&limit=5000',{
      headers:{'apikey':supaKey,'Authorization':'Bearer '+supaKey}
    });
    if(res.ok){
      const existentes=await res.json();
      existentesSet=new Set(existentes.map(e=>e.numero).filter(Boolean));
    }
  }
}catch(e){}
const nuevas=todas.filter(l=>!existentesSet.has(l.numero));
return[{json:{
  licitaciones:nuevas,count:nuevas.length,count_total:todas.length,
  count_nuevas:nuevas.length,count_existentes:todas.length-nuevas.length,
  alta:nuevas.filter(l=>l.prioridad==='alta').length,
  media:nuevas.filter(l=>l.prioridad==='media').length,
  baja:nuevas.filter(l=>l.prioridad==='baja').length,
  fechaHoy:stats.fechaHoy
}}];

const stats=$('Filtrar Nuevas').first().json;
let msg;
