  msg='*Licitaciones ComprAR - '+stats.fechaHoy+'*

*'+stats.count_nuevas+' nuevas importadas*
Alta: '+stats.alta+' / Media: '+stats.media+' / Baja: '+stats.baja+'
_('+stats.count_existentes+' existentes descartadas)_

_Revisalas en el sistema_';
}else{
  msg='*Licitaciones ComprAR - '+stats.fechaHoy+'*

Sin licitaciones nuevas hoy.
_('+stats.count_total+' ya estaban importadas)_';
}
return[{json:{message:msg}}];
